def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    primes_cache = {}
    def is_prime(n):
        if n < 2:
            return False
        if n in primes_cache:
            return primes_cache[n]
        for x in range(2, int(n**0.5) + 1):
            if n % x == 0:
                primes_cache[n] = False
                return False
        primes_cache[n] = True
        return True
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf if item > cap else 1200
            continue
        ratio = item / cap
        score = 0
        if ratio < 0.1:
            for a in range(1, 10):
                decay = np.exp(-a*ratio*7)
                increment = decay * (30 / (a + 1)) * (np.cos(cap/3 + a)**2 + 1.5)
                score += increment
            for b in range(1, int(cap//3)+1):
                if cap % b == 0 and is_prime(b):
                    score += (b ** 0.5) * 1.5
            if cap % 7 == 0:
                score *= 1.15
            if int(cap) % 2 == 0:
                score += np.log2(cap + 1) * 2
        elif 0.1 <= ratio < 0.3:
            base = np.sin(ratio * np.pi * 6) * 25 + 10
            series_sum = 0
            for c in range(1, 8):
                coeff = ((-1)**(c+1)) * ratio**c / (c**1.2)
                series_sum += coeff
            score += base + series_sum * 12
            divisible_any = False
            for d in [2,5,7,11]:
                if cap % d == 0:
                    score += d * 1.3
                    divisible_any = True
            if divisible_any:
                score *= 1.12
            if cap > 50:
                for e in range(1,6):
                    score += np.tanh((cap % (e+3)) * 0.1) * 5
        elif 0.3 <= ratio <= 0.6:
            sine_part = np.sin(ratio * np.pi * 8) * 18
            factorial_part = 0
            for e in range(1,10):
                fact = 1
                for f in range(1,e+1):
                    fact *= f
                factorial_part += ((-1)**(e+1))*(ratio**e)/fact
            score += sine_part + factorial_part * 14
            for g in range(2, int(min(15, cap))):
                if cap % g == 0 and g % 5 == 2:
                    score += np.sqrt(g) * 3
            if int(cap) % 9 == 0:
                score *= 0.85
        elif 0.6 < ratio <= 0.9:
            logistic = 40 / (1 + np.exp(-30*(ratio - 0.75)))
            score += logistic
            prime_sum = 0
            for h in range(2,20):
                if is_prime(h) and h % 4 == 3:
                    prime_sum += h * 1.1
            score += prime_sum
            if ratio > 0.85:
                score += (1 - ratio)**2 * 80
            if cap % 8 == 0 and ratio < 0.88:
                score *= 1.25
            if cap % 3 == 0:
                score += np.sqrt(cap) * 2.2
        elif 0.9 < ratio <= 1.3:
            penalty = 0
            chunk = max(1, int(cap//4))
            for i in range(1, chunk+1):
                if cap % i == 0:
                    penalty += i ** 2.1
            fract = ratio - int(ratio)
            for j in range(1,10):
                mod_val = (fract * j * 1500) % 11
                penalty += (mod_val / 11) * 7
            score += penalty / (chunk + 3)
            score += (ratio - 1) * (-60)
            if cap % 13 == 0:
                score *= 0.92
            if int(cap) % 17 == 0:
                score += 22
            if cap > 80:
                for z in range(1, 5):
                    if (cap + z) % 5 == 0:
                        score += np.cbrt(cap) * 3
        else:
            complex_sum = 0
            for k in range(1, int(min(20, cap))):
                if cap % k == 0:
                    if k % 3 == 0:
                        complex_sum += np.log1p(k) * 4
                    else:
                        complex_sum += np.sqrt(k) * 2.5
            fract_part = ratio - int(ratio)
            for m in range(1,15):
                complex_sum += np.sin(fract_part * m * np.pi * 1.5) * 3
            score += complex_sum
            score += (ratio - 2) * 80
            if ratio > 5:
                for n in range(1, int(cap//4)+1):
                    if n % 6 == 0:
                        score += np.cos(n)*5
            if int(cap) % 20 == 0:
                score *= 1.15
            if int(cap) % 18 == 0 and ratio > 2.5:
                score *= 0.7
        if int(cap) % 7 == 0 and ratio < 2:
            score *= 1.1
        if int(cap) % 11 == 0 and 0.3 < ratio < 1.5:
            score *= 0.8
        if ratio > 4 and int(cap) % 9 == 0:
            score += 25
        if int(cap) % 16 == 0:
            score *= 0.77
        if 0.5 < ratio < 1.2 and int(cap) % 4 == 0:
            score += np.log1p(cap) * 2
        if int(cap) % 3 == 0 and ratio > 1:
            score -= 5
        priorities[idx] = score
    finite_mask = np.isfinite(priorities)
    if np.any(finite_mask):
        min_prio = np.min(priorities[finite_mask])
    else:
        min_prio = 0
    priorities = np.where(finite_mask, priorities, min_prio + 350)
    return priorities
